import React, { useState, useEffect } from 'react';
import PropTypes from 'prop-types';
import { useTheme } from '../../contexts/ThemeContext';
import TextAnimation from '../common/TextAnimation';
import ProjectCard from './ProjectCard';
import styles from './Projects.module.css';

/**
 * Projects component displays a collection of project cards with filtering options.
 * It features interactive animations and responsive design.
 */
const Projects = ({ projectsData }) => {
  const { theme: currentTheme } = useTheme(); // Renamed to avoid unused variable warning
  const [activeFilter, setActiveFilter] = useState('all');
  const [animatedProjects, setAnimatedProjects] = useState([]);
  const [isVisible, setIsVisible] = useState(false);

  // Get unique categories from projects data
  const categories = ['all', ...new Set(
    projectsData.flatMap(project => project.categories || ['other'])
  )];

  // Observer to detect when the section enters viewport
  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true);
          observer.disconnect();
        }
      },
      { threshold: 0.2 }
    );

    const projectsSection = document.getElementById('projects-section');
    if (projectsSection) {
      observer.observe(projectsSection);
    }

    return () => {
      if (projectsSection) {
        observer.disconnect();
      }
    };
  }, []);

  // Animate projects gradually
  useEffect(() => {
    if (isVisible && projectsData) {
      // Stagger the animations for each project card
      const animationDelay = 150; // ms between each project animation
      
      const timer = setTimeout(() => {
        const interval = setInterval(() => {
          setAnimatedProjects(prev => {
            if (prev.length >= projectsData.length) {
              clearInterval(interval);
              return prev;
            }
            return [...prev, projectsData[prev.length]];
          });
        }, animationDelay);
        
        return () => clearInterval(interval);
      }, 500); // Initial delay before starting animations
      
      return () => clearTimeout(timer);
    }
  }, [isVisible, projectsData]);

  // Filter projects based on active category
  const filteredProjects = activeFilter === 'all'
    ? animatedProjects
    : animatedProjects.filter(project => 
      project.categories && project.categories.includes(activeFilter)
    );

  return (
    <section 
      id='projects-section' 
      className={styles.projects}
      data-testid='projects-component'
    >
      <div className={styles.container}>
        <TextAnimation 
          text='Featured Projects' 
          className={styles.title}
          animation='fadeIn'
        />
        
        {/* Filter buttons */}
        <div className={styles.filters}>
          {categories.map((category) => (
            <button
              key={category}
              className={`${styles.filterButton} ${activeFilter === category ? styles.active : ''}`}
              onClick={() => setActiveFilter(category)}
              data-testid={`filter-${category}`}
            >
              {category.charAt(0).toUpperCase() + category.slice(1)}
            </button>
          ))}
        </div>
        
        {/* Projects grid */}
        <div className={styles.projectsGrid}>
          {filteredProjects.map((project, index) => (
            <div 
              key={project.id} 
              className={styles.projectCard}
              style={{
                animationDelay: `${index * 0.15}s`,
                opacity: isVisible ? 1 : 0,
                transform: isVisible ? 'translateY(0)' : 'translateY(30px)'
              }}
            >
              <ProjectCard project={project} />
            </div>
          ))}
        </div>
        
        {/* Show a message if no projects match the filter */}
        {filteredProjects.length === 0 && (
          <div className={styles.noProjects}>
            <p>No projects found for this category.</p>
          </div>
        )}
        
        {/* Call to action button */}
        {projectsData.length > 6 && (
          <div className={styles.viewMoreContainer}>
            <a 
              href={projectsData[0]?.portfolioUrl || '#'} 
              target='_blank' 
              rel='noopener noreferrer'
              className={styles.viewMoreButton}
              data-testid='view-more-button'
            >
              View All Projects
            </a>
          </div>
        )}
      </div>
    </section>
  );
};

Projects.propTypes = {
  projectsData: PropTypes.arrayOf(
    PropTypes.shape({
      id: PropTypes.oneOfType([PropTypes.string, PropTypes.number]).isRequired,
      title: PropTypes.string.isRequired,
      description: PropTypes.string.isRequired,
      image: PropTypes.string,
      technologies: PropTypes.arrayOf(PropTypes.string).isRequired,
      categories: PropTypes.arrayOf(PropTypes.string),
      demoUrl: PropTypes.string,
      codeUrl: PropTypes.string,
      highlights: PropTypes.arrayOf(PropTypes.string),
      date: PropTypes.string,
      portfolioUrl: PropTypes.string,
    })
  ).isRequired,
};

// Mock data for development
Projects.defaultProps = {
  projectsData: [
    {
      id: 1,
      title: 'Interactive Portfolio',
      description: 'A responsive portfolio website with interactive elements and animations.',
      image: '/images/projects/portfolio.jpg',
      technologies: ['React', 'CSS', 'Three.js', 'GSAP'],
      categories: ['web', 'frontend'],
      demoUrl: 'https://example.com/portfolio',
      codeUrl: 'https://github.com/username/portfolio',
      highlights: [
        'Implemented custom theme system',
        'Created interactive 3D elements with Three.js',
        'Optimized for all devices with responsive design'
      ],
      date: 'September 2023'
    },
    {
      id: 2,
      title: 'E-commerce Platform',
      description: 'Full-stack e-commerce solution with product catalog, cart, and payment processing.',
      image: '/images/projects/ecommerce.jpg',
      technologies: ['React', 'Node.js', 'MongoDB', 'Stripe'],
      categories: ['web', 'fullstack'],
      demoUrl: 'https://example.com/ecommerce',
      codeUrl: 'https://github.com/username/ecommerce',
      highlights: [
        'Integrated secure payment processing with Stripe',
        'Built responsive product catalog with filtering',
        'Implemented user authentication and profiles'
      ],
      date: 'June 2023'
    },
    {
      id: 3,
      title: 'Weather Visualization App',
      description: 'Real-time weather data visualization with interactive maps and forecasts.',
      image: '/images/projects/weather.jpg',
      technologies: ['JavaScript', 'D3.js', 'Weather API', 'Leaflet'],
      categories: ['web', 'data'],
      demoUrl: 'https://example.com/weather',
      codeUrl: 'https://github.com/username/weather-app',
      highlights: [
        'Created interactive map visualizations with Leaflet',
        'Implemented real-time data fetching from Weather API',
        'Built responsive charts and graphs with D3.js'
      ],
      date: 'March 2023'
    },
    {
      id: 4,
      title: 'Task Management System',
      description: 'Collaborative task management application with real-time updates.',
      image: '/images/projects/tasks.jpg',
      technologies: ['React', 'Firebase', 'Material UI'],
      categories: ['web', 'productivity'],
      demoUrl: 'https://example.com/tasks',
      codeUrl: 'https://github.com/username/task-app',
      highlights: [
        'Implemented real-time updates with Firebase',
        'Created drag-and-drop task organization',
        'Built collaborative features for team projects'
      ],
      date: 'January 2023'
    },
    {
      id: 5,
      title: 'Mobile Fitness Tracker',
      description: 'Cross-platform mobile app for tracking workouts and fitness progress.',
      image: '/images/projects/fitness.jpg',
      technologies: ['React Native', 'Redux', 'Firebase'],
      categories: ['mobile', 'health'],
      demoUrl: 'https://example.com/fitness',
      codeUrl: 'https://github.com/username/fitness-app',
      highlights: [
        'Developed cross-platform mobile experience',
        'Implemented workout tracking and statistics',
        'Created personalized fitness recommendations'
      ],
      date: 'November 2022'
    },
    {
      id: 6,
      title: 'AI Content Generator',
      description: 'Web application that generates content using natural language processing.',
      image: '/images/projects/ai.jpg',
      technologies: ['Python', 'TensorFlow', 'Flask', 'React'],
      categories: ['ai', 'web'],
      demoUrl: 'https://example.com/ai-generator',
      codeUrl: 'https://github.com/username/ai-generator',
      highlights: [
        'Integrated OpenAI API for content generation',
        'Built user-friendly interface for prompt engineering',
        'Implemented content history and favorites'
      ],
      date: 'October 2022'
    }
  ],
};

export default Projects;
